 42→export function createDoorPlaceHandler({ dispatch, editorDispatch, getFloor, activeFloorId }) {
 43→  return {
 44→    onMouseMove(modelPos, e, toolState) {
 45→      const floor = getFloor(activeFloorId);
 46→      if (!floor) return;
 47→      const wall = findNearestWall(modelPos, floor.walls);
 48→
 49→      if (wall) {
 50→        const offset = projectPointOnWall(wall, modelPos);
 51→        const halfWidth = DOOR_WIDTH / 2;
 52→        const maxOffset = wallLength(wall) - halfWidth;
 53→        const clampedOffset = Math.max(halfWidth, Math.min(maxOffset, offset));
 54→        const blocked = overlapsExisting(wall.id, clampedOffset, DOOR_WIDTH, floor.doors, floor.windows);
 55→
 56→        editorDispatch({
 57→          type: 'UPDATE_TOOL_STATE',
 58→          payload: {
 59→            previewWallId: wall.id,
 60→            previewOffset: clampedOffset,
 61→            previewBlocked: blocked,
 62→            openDirection: toolState.openDirection || 'left',
 63→          },
 64→        });
 65→      } else {
 66→        editorDispatch({
 67→          type: 'UPDATE_TOOL_STATE',
 68→          payload: { previewWallId: null, previewOffset: null, previewBlocked: false, openDirection: toolState.openDirection || 'left' },
 69→        });
 70→      }
 71→    },
 72→
 73→    onMouseDown(modelPos, e, toolState) {
 74→      if (e.button !== 0) return;
 75→      if (!toolState.previewWallId || toolState.previewBlocked) return;
 76→
 77→      const openDir = toolState.openDirection || 'left';
 78→      const door = createDoor(toolState.previewWallId, toolState.previewOffset, DOOR_WIDTH, openDir);
 79→      dispatch({ type: 'DOOR_ADD', floorId: activeFloorId, door });
 80→    },
 81→
 82→    onKeyDown(e, toolState) {
 83→      if (e.key === 'Escape') {
 84→        editorDispatch({ type: 'SET_TOOL', tool: 'select' });
 85→      }
 86→      if (e.key === 'f' || e.key === 'F') {
 87→        const flipped = toolState.openDirection === 'right' ? 'left' : 'right';
 88→        editorDispatch({
 89→          type: 'UPDATE_TOOL_STATE',
 90→          payload: { openDirection: flipped },
 91→        });
 92→      }
 93→    },
 94→
 95→    getCursor(toolState) {
 96→      if (!toolState.previewWallId || toolState.previewBlocked) return 'not-allowed';
 97→      return 'copy';
 98→    },
 99→  };
100→}
