50→export function hitTestViewport(point, viewports) {
51→  for (let index = viewports.length - 1; index >= 0; index -= 1) {
52→    const viewport = viewports[index];
53→    if (pointInRect(point, viewport)) {
54→      return viewport;
55→    }
56→  }
57→  return null;
