177→export function getWallRenderData(wall, columns = []) {
178→  const syncedWall = syncWallAttachmentPoints(wall, columns);
179→  const trimStart = findTrimPoint(syncedWall.start, syncedWall.end, syncedWall.startAttachment, columns);
180→  const trimEnd = findTrimPoint(syncedWall.end, syncedWall.start, syncedWall.endAttachment, columns);
181→  const outline = makeOutline(trimStart, trimEnd, syncedWall.thickness);
182→
183→  return {
184→    wall: syncedWall,
185→    renderWall: {
186→      ...syncedWall,
187→      start: trimStart,
188→      end: trimEnd,
189→    },
190→    outline,
191→    trimStart,
192→    trimEnd,
193→  };
194→}
