 7→export function columnAxes(column) {
 8→  const angle = ((column.rotation || 0) * Math.PI) / 180;
 9→  const xAxis = { x: Math.cos(angle), y: Math.sin(angle) };
10→  const yAxis = { x: -Math.sin(angle), y: Math.cos(angle) };
11→  return { xAxis, yAxis };
