14→export function columnOutline(column) {
15→  const hw = column.width / 2, hd = column.depth / 2;
16→  const { x: cx, y: cy } = column;
17→  const corners = [
18→    { x: cx - hw, y: cy - hd }, { x: cx + hw, y: cy - hd },
19→    { x: cx + hw, y: cy + hd }, { x: cx - hw, y: cy + hd },
