24→
25→export function columnEdgeMidpoints(column) {
26→  const corners = columnOutline(column);
27→  return [
28→    midpoint(corners[0], corners[1]),
29→    midpoint(corners[1], corners[2]),
30→    midpoint(corners[2], corners[3]),
